import{_ as i,o as t,c as s,ag as a}from"./chunks/framework.eQLvDOR_.js";const c=JSON.parse('{"title":"Closing the knowledge gap with agent skills","description":"","frontmatter":{"title":"Closing the knowledge gap with agent skills","source":"https://developers.googleblog.com/closing-the-knowledge-gap-with-agent-skills/","category":"[ADK_Agent_Skills]","clipped_at":"2026-04-04","tags":["adk-agent-skills"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/ADK_Agent_Skills/ADK_Agent_Skills - Closing the knowledge gap with agent skills.md","filePath":"library/ADK_Agent_Skills/ADK_Agent_Skills - Closing the knowledge gap with agent skills.md","lastUpdated":null}'),l={name:"library/ADK_Agent_Skills/ADK_Agent_Skills - Closing the knowledge gap with agent skills.md"};function n(o,e,r,h,g,p){return t(),s("div",null,[...e[0]||(e[0]=[a(`<p>MARCH 25, 2026</p><p><a href="https://developers.googleblog.com/search/?author=Philipp+Schmid" target="_blank" rel="noreferrer">Philipp Schmid</a> Developer Relations Engineer</p><p><a href="https://developers.googleblog.com/search/?author=Mark+McDonald" target="_blank" rel="noreferrer">Mark McDonald</a> Developer Relations Engineer</p><p><img src="https://storage.googleapis.com/gweb-developer-goog-blog-assets/images/Gemini_API_Skills_Banner_v2.original.png" alt="Gemini API Skills Banner v2"></p><p>Large language models (LLMs) have fixed knowledge, being trained at a specific point in time. Software engineering practices are fast paced and change often, where new libraries are launched every day and best practices evolve quickly.</p><p>This leaves a knowledge gap that language models can&#39;t solve on their own. At Google DeepMind we see this in a few ways: our models don&#39;t know about themselves when they&#39;re trained, and they aren&#39;t necessarily aware of subtle changes in best practices (like <a href="https://ai.google.dev/gemini-api/docs/thinking#signatures" target="_blank" rel="noreferrer">thought circulation</a>) or SDK changes.</p><p>Many solutions exist, from web search tools to dedicated MCP services, but more recently, <a href="https://agentskills.io/" target="_blank" rel="noreferrer">agent skills</a> have surfaced as an extremely lightweight but potentially effective way to close this gap.</p><p>While there are strategies that we, as model builders, can implement, we wanted to explore what is possible for any SDK maintainer. Read on for what we did to build the <a href="https://github.com/google-gemini/gemini-skills/" target="_blank" rel="noreferrer">Gemini API developer skill</a> and the results it had on performance.</p><h3 id="what-we-built" tabindex="-1">What we built <a class="header-anchor" href="#what-we-built" aria-label="Permalink to &quot;What we built&quot;">​</a></h3><p>To help coding agents building with the Gemini API, we built a skill that:</p><ul><li>explains the high-level feature set of the API,</li><li>describes the current models and SDKs for each language,</li><li>demonstrates basic sample code for each SDK, and</li><li>lists the documentation entry points (as sources of truth).</li></ul><p>This is a basic set of primitive instructions that guide an agent towards using our latest models and SDKs, but importantly also refers to the documentation to encourage retrieving fresh information from the source of truth.</p><p>The skill is available on <a href="https://github.com/google-gemini/gemini-skills/" target="_blank" rel="noreferrer">GitHub</a> or install it directly into your project with:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install with Vercel skills</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> google-gemini/gemini-skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gemini-api-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install with Context7 skills</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ctx7</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /google-gemini/gemini-skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gemini-api-dev</span></span></code></pre></div><h3 id="skill-tester" tabindex="-1">Skill tester <a class="header-anchor" href="#skill-tester" aria-label="Permalink to &quot;Skill tester&quot;">​</a></h3><p>We created an evaluation harness with 117 prompts that generate Python or TypeScript code using the Gemini SDKs that are used to evaluate skill performance.</p><p>The prompts evaluate across different categories, including agentic coding tasks, building chatbots, document processing, streaming content and a number of specific SDK features.</p><p>We ran these tests both in &quot;vanilla&quot; mode (directly prompting the model) and with the skill enabled. To enable the skill, the model is given the <a href="https://github.com/google-gemini/gemini-cli/blob/bb7bb11736c363f3368a61f4bc4557ab8bb660a2/packages/core/src/prompts/snippets.ts#L213-L233" target="_blank" rel="noreferrer">same system instruction</a> that the Gemini CLI uses, and two tools: <code>activate_skill</code> and <code>fetch_url</code> (for downloading the docs).</p><p>A prompt is considered a failure if it uses one of our old SDKs.</p><h3 id="skills-work-but-they-need-reasoning" tabindex="-1">Skills work, but they need reasoning <a class="header-anchor" href="#skills-work-but-they-need-reasoning" aria-label="Permalink to &quot;Skills work, but they need reasoning&quot;">​</a></h3><p>The top-line results:</p><p><img src="https://storage.googleapis.com/gweb-developer-goog-blog-assets/images/Gemini_API_Skill_Benchmark_-_Model.original.png" alt="Gemini API Skill Benchmark - Model"></p><ul><li>The latest Gemini 3 series of models achieve excellent results with the addition of the <code>gemini-api-dev</code> skill, notably coming from a low baseline without it (6.8% for both 3.0 Pro and Flash, 28% for 3.1 Pro).</li><li>The older 2.5 series of models also benefit, but nowhere near as much. Using modern models with strong reasoning support makes a difference.</li></ul><h3 id="all-categories-performed-well" tabindex="-1">All categories performed well <a class="header-anchor" href="#all-categories-performed-well" aria-label="Permalink to &quot;All categories performed well&quot;">​</a></h3><p>Adding the skill was effective across almost all domains for the top-performing model (<code>gemini-3.1-pro-preview</code>).</p><p><img src="https://storage.googleapis.com/gweb-developer-goog-blog-assets/images/Gemini_API_Skill_Benchmark_-_Domain.original.png" alt="Gemini API Skill Benchmark - Domain"></p><p><em>SDK Usage</em> had the lowest pass rate, at 95%. There is no stand-out reason for this; the failed prompts cover a range of tasks that include some difficult or unclear requests, but notably they include prompts that explicitly request Gemini 2.0 models.</p><p>Here&#39;s an example from the <em>SDK usage</em> category that failed across all models.</p><blockquote><p><sup>When I use the Python api with the gemini 2.0 flash model, and when the output is quite long, the returned content will be an array of output chunks instead of the whole thing. i guess it was doing some kind of streaming type of input. how to turn this off and get the whole output together</sup></p></blockquote><h3 id="skill-issues" tabindex="-1">Skill issues <a class="header-anchor" href="#skill-issues" aria-label="Permalink to &quot;Skill issues&quot;">​</a></h3><p>These initial results are quite encouraging, but we know from <a href="https://vercel.com/blog/agents-md-outperforms-skills-in-our-agent-evals" target="_blank" rel="noreferrer">Vercel&#39;s work</a> that direct instruction through <code>AGENTS.md</code> can be more effective than using skills, so we are exploring other ways to supply live knowledge of SDKs, such as directly using MCPs for documentation.</p><p>Skill simplicity is a huge benefit, but right now there isn&#39;t a great skill update story, other than requiring users to update manually. In the long term this could leave old skill information in user&#39;s workspaces, doing more harm than good.</p><p>Despite these minor issues we’re still excited to start using skills in our workflows. The Gemini API skill is still fairly new, but we’re keeping it maintained as we push model updates, and we will be exploring different avenues for improving it. Follow <a href="https://x.com/m4rkmc" target="_blank" rel="noreferrer">Mark</a> and <a href="https://x.com/_philschmid" target="_blank" rel="noreferrer">Phil</a> for updates as we tune the skill, and don’t forget to <a href="https://github.com/google-gemini/gemini-skills/" target="_blank" rel="noreferrer">try it out</a> and <a href="https://github.com/google-gemini/gemini-skills/issues" target="_blank" rel="noreferrer">let us know</a> your feedback!</p>`,33)])])}const k=i(l,[["render",n]]);export{c as __pageData,k as default};
